AUT,EAASQ,YAAYR,EAASY,YAF7K,GAAGF,KAAKX,YAAYwB,wBAG7B,EAIDV,OAAO4E,OAAOxB,EAAgByB,UAAW9C,EAAa,CAAEI,eAAe,KCtbvE,MAAM2C,EAMF,WAAA5F,GAMIW,KAAKkF,iBAAmB,KAOxBlF,KAAKmF,oBAAsB,KAO3BnF,KAAKoF,WAAa,EACtB,CAgBA,WAAAC,CAAY/F,GACR,GAAiB,OAAbA,KAAuBA,aAAoBF,GAC3C,MAAM,IAAIkG,UAAU,mEAaxB,OAVAtF,KAAKkF,iBAAmB5F,EACxBU,KAAKmF,oBAAsB7F,EAAW,CAClCG,SAAUH,EAASG,SACnBC,UAAWJ,EAASI,WACpB,KAEa,OAAbJ,GACAU,KAAKuF,mBAGFvF,IACX,CAaA,kBAAAwF,GACI,OAAOxF,KAAKkF,gBAChB,CAaA,qBAAAO,GACI,OAAOzF,KAAKmF,oBAAsB,IAAKnF,KAAKmF,qBAAwB,IACxE,CAaA,WAAAO,GACI,OAAiC,OAA1B1F,KAAKkF,gBAChB,CAoBA,SAAAjE,CAAU0E,GACN,GAAwB,mBAAbA,EACP,MAAM,IAAIL,UAAU,+CAKxB,OAHAtF,KAAKoF,WAAWQ,KAAKD,GAGd,KACH,MAAME,EAAQ7F,KAAKoF,WAAWU,QAAQH,GAClCE,GAAQ,GACR7F,KAAKoF,WAAWW,OAAOF,EAAO,GAG1C,CAcA,WAAA1E,CAAYwE,GACR,MAAME,EAAQ7F,KAAKoF,WAAWU,QAAQH,GACtC,OAAIE,GAAQ,IACR7F,KAAKoF,WAAWW,OAAOF,EAAO,IACvB,EAGf,CAUA,gBAAA9D,GACI,OAAO/B,KAAKoF,WAAW/E,MAC3B,CAUA,cAAA2F,GACIhG,KAAKoF,WAAa,EACtB,CASA,KAAAa,GACIjG,KAAKkF,iBAAmB,KACxBlF,KAAKmF,oBAAsB,IAC/B,CAUA,gBAAAI,GACI,MAAMW,EAAgB,CAClB5G,SAAUU,KAAKkF,iBACfiB,YAAanG,KAAKyF,yBAGtBzF,KAAKoF,WAAW5D,QAAQmE,IACpB,IACIA,EAASO,EACb,OAASvJ,GACLC,EAAK,2CAA4CD,EACrD,GAER,CAWA,QAAAiE,GAKI,MAAO,6BAJQZ,KAAKkF,iBAAmB,YAAc,wBACtClF,KAAKmF,oBAChB,IAAInF,KAAKmF,oBAAoB1F,SAAS8E,QAAQ,OAAOvE,KAAKmF,oBAAoBzF,UAAU6E,QAAQ,MAChG,sBAC8EvE,KAAKoF,WAAW/E,QACtG","names":["LOG_LEVELS","none","error","warn","log","debug","logConfig","level","enabled","_getConfiguredLevel","process","define_process_env_default","GUIA_LOG_LEVEL","toLowerCase","window","localStorage","stored","getItem","e","location","hostname","startsWith","levelName","_initializeConfig","_isLevelEnabled","formatTimestamp","Date","toISOString","message","params","console","calculateDistance","lat1","lon1","lat2","lon2","Math","PI","a","sin","cos","atan2","sqrt","GeoPosition","constructor","position","rawCoords","coords","latitude","longitude","accuracy","altitude","altitudeAccuracy","heading","speed","this","geolocationPosition","timestamp","Object","keys","length","accuracyQuality","getAccuracyQuality","freeze","calculateAccuracyQuality","distanceTo","otherPosition","toString","name","ObserverSubject","observers","functionObservers","subscribe","observer","unsubscribe","filter","o","notifyObservers","args","forEach","update","subscribeFunction","observerFunction","unsubscribeFunction","fn","notifyFunctionObservers","getObserverCount","getFunctionObserverCount","clearAllObservers","withObserver","options","checkNull","className","excludeNotify","mixin","observerSubject","setupParams","createDefaultConfig","__vitePreload","async","import","then","n","d","__VITE_PRELOAD__","url","err","notAcceptedAccuracy","minimumDistanceChange","trackingInterval","PositionManager","static","getInstance","instance","tsPosicaoAtual","lastModified","lastPosition","posEvent","data","bUpdateCurrPos","Array","isArray","includes","distance","timeElapsed","timeElapsedSeconds","toFixed","distanceExceeded","timeExceeded","minimumTimeChange","strCurrPosNotUpdate","errorMessage","strImmediateAddressUpdate","strCurrPosUpdate","assign","prototype","GeocodingState","_currentPosition","_currentCoordinates","_observers","setPosition","TypeError","_notifyObservers","getCurrentPosition","getCurrentCoordinates","hasPosition","callback","push","index","indexOf","splice","clearObservers","clear","stateSnapshot","coordinates"],"ignoreList":[],"sources":["../../src/utils/logger.js","../../src/utils/distance.js","../../src/core/GeoPosition.js","../../src/core/ObserverSubject.js","../../src/utils/ObserverMixin.js","../../src/core/PositionManager.js","../../src/core/GeocodingState.js"],"sourcesContent":["'use strict';\n\n/**\n * Logging utilities with timestamp formatting and environment-aware configuration.\n * \n * Provides centralized logging with environment-based control to prevent\n * console pollution in production. All functions check the logging level\n * before outputting to console.\n * \n * **Environment Configuration**:\n * - Set `GUIA_LOG_LEVEL` environment variable or localStorage key\n * - Levels: 'none', 'error', 'warn', 'log', 'debug' (default: 'log')\n * - Production detection via NODE_ENV or manual configuration\n * \n * @module utils/logger\n * @since 0.9.0-alpha\n * @author Marcelo Pereira Barbosa\n */\n\n/**\n * Log levels in ascending order of verbosity.\n * @private\n */\nconst LOG_LEVELS = {\n\tnone: 0,\n\terror: 1,\n\twarn: 2,\n\tlog: 3,\n\tdebug: 4\n};\n\n/**\n * Current logging configuration.\n * @private\n */\nlet logConfig = {\n\tlevel: LOG_LEVELS.log,\n\tenabled: true,\n\ttimestamp: true\n};\n\n/**\n * Detects if running in production environment.\n * \n * @returns {boolean} True if production environment detected\n * @private\n */\nconst _isProduction = () => {\n\t// Node.js environment check\n\tif (typeof process !== 'undefined' && process.env) {\n\t\treturn process.env.NODE_ENV === 'production';\n\t}\n\t// Browser check for production indicators\n\tif (typeof window !== 'undefined') {\n\t\treturn window.location?.hostname !== 'localhost' && \n\t\t       !window.location?.hostname?.startsWith('127.0.0.1');\n\t}\n\treturn false;\n};\n\n/**\n * Gets configured log level from environment or localStorage.\n * \n * Priority:\n * 1. GUIA_LOG_LEVEL environment variable (Node.js)\n * 2. localStorage.GUIA_LOG_LEVEL (browser)\n * 3. Default based on environment (production = 'error', development = 'log')\n * \n * @returns {string} Log level name\n * @private\n */\nconst _getConfiguredLevel = () => {\n\t// Check Node.js environment variable\n\tif (typeof process !== 'undefined' && process.env?.GUIA_LOG_LEVEL) {\n\t\treturn process.env.GUIA_LOG_LEVEL.toLowerCase();\n\t}\n\t// Check browser localStorage (safely)\n\tif (typeof window !== 'undefined' && typeof localStorage !== 'undefined') {\n\t\ttry {\n\t\t\tconst stored = localStorage.getItem('GUIA_LOG_LEVEL');\n\t\t\tif (stored) return stored.toLowerCase();\n\t\t} catch (e) {\n\t\t\t// localStorage not available or blocked, continue to default\n\t\t}\n\t}\n\t// Default based on environment\n\treturn _isProduction() ? 'error' : 'log';\n};\n\n/**\n * Initializes logging configuration.\n * Called automatically on module load.\n * \n * @private\n */\nconst _initializeConfig = () => {\n\tconst levelName = _getConfiguredLevel();\n\tlogConfig.level = LOG_LEVELS[levelName] ?? LOG_LEVELS.log;\n\tlogConfig.enabled = logConfig.level > LOG_LEVELS.none;\n};\n\n// Initialize on module load\n_initializeConfig();\n\n/**\n * Checks if a specific log level is enabled.\n * \n * @param {number} level - Log level to check\n * @returns {boolean} True if level is enabled\n * @private\n */\nconst _isLevelEnabled = (level) => {\n\treturn logConfig.enabled && logConfig.level >= level;\n};\n\n/**\n * Formats current timestamp for log messages.\n * \n * @returns {string} ISO 8601 timestamp\n * \n * @example\n * formatTimestamp(); // \"2025-10-15T04:33:48.006Z\"\n * \n * @since 0.9.0-alpha\n */\nexport const formatTimestamp = () => new Date().toISOString();\n\n/**\n * Logs info message with timestamp (if LOG level enabled).\n * \n * Respects environment configuration - disabled in production by default.\n * Use for general informational messages during development.\n * \n * @param {string} message - Message to log\n * @param {...any} params - Additional parameters\n * \n * @example\n * log('Position updated', { lat: -23.5505, lon: -46.6333 });\n * // Output: [2025-10-15T04:33:48.006Z] Position updated { lat: -23.5505, lon: -46.6333 }\n * // (only if log level >= 'log')\n * \n * @since 0.9.0-alpha\n */\nexport const log = (message, ...params) => {\n\tif (_isLevelEnabled(LOG_LEVELS.log)) {\n\t\tconsole.log(`[${formatTimestamp()}]`, message, ...params);\n\t}\n};\n\n/**\n * Logs warning message with timestamp (if WARN level enabled).\n * \n * Respects environment configuration. Use for non-critical issues\n * that should be visible in production.\n * \n * @param {string} message - Warning message\n * @param {...any} params - Additional parameters\n * \n * @example\n * warn('Low accuracy detected', { accuracy: 500 });\n * // Output: [2025-10-15T04:33:48.006Z] Low accuracy detected { accuracy: 500 }\n * // (only if log level >= 'warn')\n * \n * @since 0.9.0-alpha\n */\nexport const warn = (message, ...params) => {\n\tif (_isLevelEnabled(LOG_LEVELS.warn)) {\n\t\tconsole.warn(`[${formatTimestamp()}]`, message, ...params);\n\t}\n};\n\n/**\n * Logs error message with timestamp (if ERROR level enabled).\n * \n * Always enabled except when explicitly set to 'none'. Use for\n * critical errors that need attention even in production.\n * \n * @param {string} message - Error message\n * @param {...any} params - Additional parameters\n * \n * @example\n * error('Geolocation failed', { code: 1, message: 'Permission denied' });\n * // Output: [2025-10-15T04:33:48.006Z] Geolocation failed { code: 1, message: 'Permission denied' }\n * // (only if log level >= 'error')\n * \n * @since 0.9.0-alpha\n */\nexport const error = (message, ...params) => {\n\tif (_isLevelEnabled(LOG_LEVELS.error)) {\n\t\tconsole.error(`[${formatTimestamp()}]`, message, ...params);\n\t}\n};\n\n/**\n * Logs debug message with timestamp (if DEBUG level enabled).\n * \n * Only enabled when explicitly configured. Use for verbose\n * debugging information during development.\n * \n * @param {string} message - Debug message\n * @param {...any} params - Additional parameters\n * \n * @example\n * debug('Observer notified', { observerCount: 5 });\n * // Output: [2025-10-15T04:33:48.006Z] Observer notified { observerCount: 5 }\n * // (only if log level >= 'debug')\n * \n * @since 0.9.0-alpha\n */\nexport const debug = (message, ...params) => {\n\tif (_isLevelEnabled(LOG_LEVELS.debug)) {\n\t\tconsole.debug(`[${formatTimestamp()}] [DEBUG]`, message, ...params);\n\t}\n};\n\n/**\n * Configures logging at runtime.\n * \n * Allows dynamic adjustment of logging behavior without restarting.\n * Changes persist in memory only (not saved to localStorage automatically).\n * \n * @param {Object} options - Configuration options\n * @param {string} [options.level] - Log level: 'none', 'error', 'warn', 'log', 'debug'\n * @param {boolean} [options.enabled] - Enable/disable all logging\n * @param {boolean} [options.timestamp] - Include timestamps in logs\n * \n * @example\n * // Disable all logging\n * setLogLevel({ enabled: false });\n * \n * // Set to error-only in production\n * setLogLevel({ level: 'error' });\n * \n * // Enable debug mode for development\n * setLogLevel({ level: 'debug' });\n * \n * @since 0.9.0-alpha\n * @param {Object} [options] - Configuration options\n * @param {string} [options.level] - Log level ('debug', 'info', 'warn', 'error')\n * @param {boolean} [options.enabled] - Enable/disable logging\n * @returns {void}\n */\nexport const setLogLevel = (options = {}) => {\n\tif (options.level && LOG_LEVELS[options.level] !== undefined) {\n\t\tlogConfig.level = LOG_LEVELS[options.level];\n\t}\n\tif (typeof options.enabled === 'boolean') {\n\t\tlogConfig.enabled = options.enabled;\n\t}\n\tif (typeof options.timestamp === 'boolean') {\n\t\tlogConfig.timestamp = options.timestamp;\n\t}\n};\n\n/**\n * Gets current logging configuration.\n * \n * @returns {Object} Current configuration with level name and enabled state\n * \n * @example\n * const config = getLogLevel();\n * console.log(config); // { level: 'log', levelName: 'log', enabled: true }\n * \n * @since 0.9.0-alpha\n */\nexport const getLogLevel = () => {\n\tconst levelName = Object.keys(LOG_LEVELS).find(\n\t\tkey => LOG_LEVELS[key] === logConfig.level\n\t) || 'log';\n\t\n\treturn {\n\t\tlevel: logConfig.level,\n\t\tlevelName,\n\t\tenabled: logConfig.enabled,\n\t\ttimestamp: logConfig.timestamp,\n\t\tisProduction: _isProduction()\n\t};\n};\n","'use strict';\nimport { log, warn, error } from './logger.js';\n\n/**\n * Distance calculation utilities for geolocation.\n * \n * Pure functions for geographic distance calculations using the Haversine formula.\n * All functions are referentially transparent with no side effects.\n * \n * @module utils/distance\n * @since 0.9.0-alpha\n * @author Marcelo Pereira Barbosa\n */\n\n/**\n * Earth's mean radius in meters used for Haversine distance calculations.\n * @constant {number}\n */\nexport const EARTH_RADIUS_METERS = 6371e3;\n\n/**\n * Calculates the great-circle distance between two geographic points using the Haversine formula.\n * \n * The Haversine formula determines the shortest distance over the earth's surface between two points\n * given their latitude and longitude coordinates. This implementation assumes a spherical Earth\n * with radius 6,371,000 meters (mean radius).\n * \n * Formula: d = R × c\n * Where:\n * - R = Earth's radius (6,371,000 meters)\n * - c = 2 × atan2(√a, √(1−a))\n * - a = sin²(Δφ/2) + cos(φ1) × cos(φ2) × sin²(Δλ/2)\n * - φ = latitude in radians\n * - λ = longitude in radians\n * - Δφ = difference in latitudes\n * - Δλ = difference in longitudes\n * \n * @param {number} lat1 - Latitude of first point in decimal degrees (-90 to 90)\n * @param {number} lon1 - Longitude of first point in decimal degrees (-180 to 180)\n * @param {number} lat2 - Latitude of second point in decimal degrees (-90 to 90)\n * @param {number} lon2 - Longitude of second point in decimal degrees (-180 to 180)\n * @returns {number} Distance in meters between the two points\n * \n * @example\n * // Distance between São Paulo and Rio de Janeiro\n * const distance = calculateDistance(-23.5505, -46.6333, -22.9068, -43.1729);\n * log(distance); // ~357,710 meters (357.7 km)\n * \n * @see {@link https://en.wikipedia.org/wiki/Haversine_formula} Haversine formula on Wikipedia\n * @see {@link https://www.movable-type.co.uk/scripts/latlong.html} Calculate distance, bearing and more\n * \n * @since 0.9.0-alpha\n * @author Marcelo Pereira Barbosa\n */\nexport const calculateDistance = (lat1, lon1, lat2, lon2) => {\n\tconst R = EARTH_RADIUS_METERS; // Earth radius in meters (mean radius)\n\tconst φ1 = (lat1 * Math.PI) / 180; // Convert latitude 1 to radians\n\tconst φ2 = (lat2 * Math.PI) / 180; // Convert latitude 2 to radians\n\tconst Δφ = ((lat2 - lat1) * Math.PI) / 180; // Difference in latitude (radians)\n\tconst Δλ = ((lon2 - lon1) * Math.PI) / 180; // Difference in longitude (radians)\n\n\t// Haversine formula core calculation\n\tconst a = Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +\n\t\tMath.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2);\n\tconst c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));\n\n\treturn R * c; // Distance in meters\n};\n\n/**\n * Creates a promise that resolves after the specified delay.\n * \n * @param {number} ms - Delay in milliseconds\n * @returns {Promise<void>} Promise that resolves after the delay\n * \n * @example\n * await delay(1000); // Wait 1 second\n * \n * @since 0.9.0-alpha\n */\nexport const delay = (ms) => new Promise((res) => setTimeout(res, ms));\n","'use strict';\nimport { log, warn, error } from '../utils/logger.js';\n\n/**\n * Geographic position data wrapper with convenience methods.\n * \n * Provides an immutable wrapper around browser Geolocation API position data,\n * adding convenience methods for distance calculations and accuracy assessment.\n * \n * @module core/GeoPosition\n * @since 0.6.0-alpha\n * @author Marcelo Pereira Barbosa\n */\n\nimport { calculateDistance } from '../utils/distance.js';\n\n/**\n * Represents a geographic position with enhanced methods.\n * \n * @class\n * @immutable All instances are frozen after creation\n */\nclass GeoPosition {\n\tconstructor(position) {\n\t\t// FIX: GeolocationCoordinates uses getters (not enumerable), spread operator creates empty object\n\t\t// Extract properties manually to handle browser Geolocation API correctly\n\t\tconst rawCoords = position?.coords;\n\t\t\n\t\t// Create defensive copy with explicit property extraction\n\t\t// This handles both plain objects (tests) and GeolocationCoordinates (browser)\n\t\tconst coords = rawCoords ? {\n\t\t\tlatitude: rawCoords.latitude,\n\t\t\tlongitude: rawCoords.longitude,\n\t\t\taccuracy: rawCoords.accuracy,\n\t\t\taltitude: rawCoords.altitude,\n\t\t\taltitudeAccuracy: rawCoords.altitudeAccuracy,\n\t\t\theading: rawCoords.heading,\n\t\t\tspeed: rawCoords.speed\n\t\t} : {};\n\t\t\n\t\tthis.geolocationPosition = position ? { \n\t\t\ttimestamp: position.timestamp,\n\t\t\tcoords: coords \n\t\t} : null;\n\t\tthis.coords = Object.keys(coords).length > 0 ? coords : null;\n\t\tthis.latitude = coords.latitude;\n\t\tthis.longitude = coords.longitude;\n\t\tthis.accuracy = coords.accuracy;\n\t\tthis.accuracyQuality = GeoPosition.getAccuracyQuality(\n\t\t\tcoords.accuracy,\n\t\t);\n\t\tthis.altitude = coords.altitude;\n\t\tthis.altitudeAccuracy = coords.altitudeAccuracy;\n\t\tthis.heading = coords.heading;\n\t\tthis.speed = coords.speed;\n\t\tthis.timestamp = position?.timestamp;\n\t\tObject.freeze(this); // Make the instance immutable\n\t}\n\n\t/**\n\t * Classifies GPS accuracy into quality levels based on accuracy value in meters.\n\t * \n\t * Provides a standardized way to assess the quality of GPS position data\n\t * based on the accuracy reported by the device. Lower values indicate better accuracy.\n\t * \n\t * Quality Levels:\n\t * - excellent: ≤ 10 meters (high precision, suitable for all applications)\n\t * - good: 11-30 meters (good precision, suitable for most applications)  \n\t * - medium: 31-100 meters (moderate precision, may be acceptable for some uses)\n\t * - bad: 101-200 meters (poor precision, generally not recommended)\n\t * - very bad: > 200 meters (very poor precision, should be rejected)\n\t * \n\t * @static\n\t * @param {number} accuracy - GPS accuracy value in meters from GeolocationCoordinates\n\t * @returns {string} Quality classification: 'excellent'|'good'|'medium'|'bad'|'very bad'\n\t * \n\t * @example\n\t * // Classify different accuracy levels\n\t * log(GeoPosition.getAccuracyQuality(5));   // 'excellent'\n\t * log(GeoPosition.getAccuracyQuality(25));  // 'good'\n\t * log(GeoPosition.getAccuracyQuality(75));  // 'medium'\n\t * log(GeoPosition.getAccuracyQuality(150)); // 'bad'\n\t * log(GeoPosition.getAccuracyQuality(500)); // 'very bad'\n\t * \n\t * @see {@link https://developer.mozilla.org/en-US/docs/Web/API/GeolocationCoordinates/accuracy} GeolocationCoordinates.accuracy\n\t * @since 0.6.0-alpha\n\t */\n\tstatic getAccuracyQuality(accuracy) {\n\t\tif (accuracy <= 10) {\n\t\t\treturn \"excellent\";\n\t\t} else if (accuracy <= 30) {\n\t\t\treturn \"good\";\n\t\t} else if (accuracy <= 100) {\n\t\t\treturn \"medium\";\n\t\t} else if (accuracy <= 200) {\n\t\t\treturn \"bad\";\n\t\t} else {\n\t\t\treturn \"very bad\";\n\t\t}\n\t}\n\n\t/**\n\t * Calculates the accuracy quality for the current position.\n\t * \n\t * Convenience method that applies the static getAccuracyQuality() method\n\t * to this instance's accuracy value.\n\t * \n\t * @returns {string} Quality classification for current position accuracy\n\t * \n\t * @example\n\t * const manager = PositionManager.getInstance(position);\n\t * log(manager.calculateAccuracyQuality()); // 'good'\n\t * \n\t * @since 0.6.0-alpha\n\t * @deprecated Use accuracyQuality property instead - this method has a bug (calls undefined getAccuracyQuality)\n\t */\n\tcalculateAccuracyQuality() {\n\t\treturn getAccuracyQuality(this.accuracy);\n\t}\n\n\t/**\n\t * Calculates the distance between this position and another position.\n\t * \n\t * Uses the Haversine formula to compute the great-circle distance between\n\t * two geographic points. Useful for determining how far the device has\n\t * moved or measuring distances to other locations.\n\t * \n\t * @param {Object} otherPosition - Other position to calculate distance to\n\t * @param {number} otherPosition.latitude - Latitude of other position in decimal degrees\n\t * @param {number} otherPosition.longitude - Longitude of other position in decimal degrees\n\t * @returns {number} Distance in meters between the two positions\n\t * \n\t * @example\n\t * const manager = PositionManager.getInstance(currentPosition);\n\t * const restaurant = { latitude: -23.5489, longitude: -46.6388 };\n\t * const distance = manager.distanceTo(restaurant);\n\t * log(`Restaurant is ${Math.round(distance)} meters away`);\n\t * \n\t * @see {@link calculateDistance} - The underlying distance calculation function\n\t * @since 0.6.0-alpha\n\t */\n\tdistanceTo(otherPosition) {\n\t\treturn calculateDistance(\n\t\t\tthis.latitude,\n\t\t\tthis.longitude,\n\t\t\totherPosition.latitude,\n\t\t\totherPosition.longitude,\n\t\t);\n\t}\n\n\t/**\n\t * Returns a string representation of the GeoPosition instance.\n\t * \n\t * Provides a formatted summary of key position properties for debugging\n\t * and logging purposes. Includes class name and essential position data\n\t * following the same format as PositionManager.toString().\n\t * \n\t * @returns {string} Formatted string with position details\n\t * \n\t * @example\n\t * const position = new GeoPosition(geolocationPosition);\n\t * log(position.toString());\n\t * // Output: \"GeoPosition: -23.5505, -46.6333, good, 760, 0, 0, 1634567890123\"\n\t * \n\t * @since 0.6.0-alpha\n\t */\n\ttoString() {\n\t\tif (!this.latitude || !this.longitude) {\n\t\t\treturn `${this.constructor.name}: No position data`;\n\t\t}\n\t\treturn `${this.constructor.name}: ${this.latitude}, ${this.longitude}, ${this.accuracyQuality}, ${this.altitude}, ${this.speed}, ${this.heading}, ${this.timestamp}`;\n\t}\n}\n\nexport default GeoPosition;\n","'use strict';\n\n/**\n * ObserverSubject - Centralizes observer pattern implementation with immutable state updates\n * \n * This class provides a reusable implementation of the observer pattern,\n * supporting both object-based observers (with update methods) and function-based observers.\n * It eliminates code duplication across multiple classes that need observer functionality.\n * \n * **Referential Transparency & Immutability:**\n * - Observer arrays are managed immutably using spread operator and filter\n * - subscribe() and unsubscribe() create new arrays instead of mutating in place\n * - State transitions are predictable and referentially transparent\n * - Each operation returns void but updates state without direct mutation\n * \n * @module core/ObserverSubject\n * @class\n * @since 0.9.0-alpha\n * \n * @example\n * // Using in a class via composition\n * class MyClass {\n *   constructor() {\n *     this.observerSubject = new ObserverSubject();\n *   }\n *   \n *   subscribe(observer) {\n *     this.observerSubject.subscribe(observer);\n *   }\n *   \n *   notify(...args) {\n *     this.observerSubject.notifyObservers(...args);\n *   }\n * }\n * \n * @example\n * // Immutable observer management\n * const subject = new ObserverSubject();\n * const observer1 = { update: () => {} };\n * const observer2 = { update: () => {} };\n * \n * subject.subscribe(observer1);\n * const array1 = subject.observers; // [observer1]\n * \n * subject.subscribe(observer2);\n * const array2 = subject.observers; // [observer1, observer2]\n * \n * // array1 and array2 are different instances (immutable pattern)\n * log(array1 !== array2); // true\n * log(array1.length); // 1 (original unchanged)\n * log(array2.length); // 2 (new array created)\n */\n\nimport { log } from '../utils/logger.js';\n\nclass ObserverSubject {\n\t/**\n\t * Creates a new ObserverSubject instance.\n\t * Initializes empty arrays for both object and function observers.\n\t */\n\tconstructor() {\n\t\tthis.observers = [];\n\t\tthis.functionObservers = [];\n\t}\n\n\t/**\n\t * Subscribes an observer object to receive notifications.\n\t * The observer must have an update() method that will be called on notifications.\n\t * \n\t * **Immutable Pattern:** Creates a new array using spread operator instead of \n\t * mutating the existing observers array. This ensures referential transparency\n\t * and makes state transitions predictable.\n\t * \n\t * @param {Object} observer - Observer object with an update method\n\t * @param {Function} observer.update - Method called when notifying observers\n\t * @returns {void}\n\t * \n\t * @example\n\t * const observer = {\n\t *   update: (subject, ...args) => {\n\t *     log('Notified with:', args);\n\t *   }\n\t * };\n\t * observerSubject.subscribe(observer);\n\t * \n\t * @example\n\t * // Demonstrating immutability\n\t * const originalArray = observerSubject.observers;\n\t * observerSubject.subscribe(observer);\n\t * const newArray = observerSubject.observers;\n\t * log(originalArray !== newArray); // true - new array created\n\t */\n\tsubscribe(observer) {\n\t\tif (observer) {\n\t\t\tthis.observers = [...this.observers, observer];\n\t\t}\n\t}\n\n\t/**\n\t * Unsubscribes an observer object from notifications.\n\t * \n\t * **Immutable Pattern:** Uses filter to create a new array without the observer,\n\t * instead of mutating the existing array. This maintains referential transparency.\n\t * \n\t * @param {Object} observer - Observer object to remove\n\t * @returns {void}\n\t * \n\t * @example\n\t * observerSubject.unsubscribe(observer);\n\t * \n\t * @example\n\t * // Demonstrating immutability\n\t * const arrayBefore = observerSubject.observers;\n\t * observerSubject.unsubscribe(observer);\n\t * const arrayAfter = observerSubject.observers;\n\t * log(arrayBefore !== arrayAfter); // true - new array created\n\t */\n\tunsubscribe(observer) {\n\t\tthis.observers = this.observers.filter((o) => o !== observer);\n\t}\n\n\t/**\n\t * Notifies all subscribed object observers.\n\t * Calls the update() method on each observer with the provided arguments.\n\t * \n\t * @param {...*} args - Arguments to pass to each observer's update method\n\t * @returns {void}\n\t * \n\t * @example\n\t * observerSubject.notifyObservers(data1, data2, eventType);\n\t */\n\tnotifyObservers(...args) {\n\t\tlog(\"+++ (100) (ObserverSubject) Notifying observers with args:\", args);\n\t\tthis.observers.forEach((observer) => {\n\t\t\tif (typeof observer.update === \"function\") {\n\t\t\t\tlog(\"+++ (101) (ObserverSubject) Notifying observer:\", observer);\n\t\t\t\tobserver.update(...args);\n\t\t\t}\n\t\t});\n\t}\n\n\t/**\n\t * Subscribes a function to receive notifications.\n\t * \n\t * **Immutable Pattern:** Creates a new array using spread operator instead of \n\t * mutating the existing functionObservers array.\n\t * \n\t * @param {Function} observerFunction - Function to be called on notifications\n\t * @returns {void}\n\t * \n\t * @example\n\t * const handler = (subject, ...args) => {\n\t *   log('Function observer notified:', args);\n\t * };\n\t * observerSubject.subscribeFunction(handler);\n\t */\n\tsubscribeFunction(observerFunction) {\n\t\tif (observerFunction) {\n\t\t\tthis.functionObservers = [...this.functionObservers, observerFunction];\n\t\t}\n\t}\n\n\t/**\n\t * Unsubscribes a function from notifications.\n\t * \n\t * **Immutable Pattern:** Uses filter to create a new array without the function,\n\t * maintaining immutability and referential transparency.\n\t * \n\t * @param {Function} observerFunction - Function to remove\n\t * @returns {void}\n\t * \n\t * @example\n\t * observerSubject.unsubscribeFunction(handler);\n\t */\n\tunsubscribeFunction(observerFunction) {\n\t\tthis.functionObservers = this.functionObservers.filter(\n\t\t\t(fn) => fn !== observerFunction,\n\t\t);\n\t}\n\n\t/**\n\t * Notifies all subscribed function observers.\n\t * \n\t * @param {...*} args - Arguments to pass to each observer function\n\t * @returns {void}\n\t * \n\t * @example\n\t * observerSubject.notifyFunctionObservers(data1, data2);\n\t */\n\tnotifyFunctionObservers(...args) {\n\t\tthis.functionObservers.forEach((fn) => {\n\t\t\tif (typeof fn === \"function\") {\n\t\t\t\tfn(...args);\n\t\t\t}\n\t\t});\n\t}\n\n\t/**\n\t * Gets the count of subscribed object observers.\n\t * \n\t * @returns {number} Number of subscribed observers\n\t */\n\tgetObserverCount() {\n\t\treturn this.observers.length;\n\t}\n\n\t/**\n\t * Gets the count of subscribed function observers.\n\t * \n\t * @returns {number} Number of subscribed function observers\n\t */\n\tgetFunctionObserverCount() {\n\t\treturn this.functionObservers.length;\n\t}\n\n\t/**\n\t * Clears all observers (both object and function observers).\n\t * \n\t * @returns {void}\n\t */\n\tclearAllObservers() {\n\t\tthis.observers = [];\n\t\tthis.functionObservers = [];\n\t}\n}\n\nexport default ObserverSubject;\n","'use strict';\n\nimport { warn } from './logger.js';\n\n/**\n * Observer Pattern Mixin for delegating to ObserverSubject.\n * \n * This mixin eliminates code duplication by providing standard observer pattern\n * delegation methods. It handles subscription management, unsubscription, and\n * notification with optional null checking and logging.\n * \n * **Benefits**:\n * - Eliminates 15+ lines of boilerplate per class\n * - Consistent observer interface across all classes\n * - Optional null checking and validation\n * - Backward compatible with existing implementations\n * \n * **Usage Patterns**:\n * \n * 1. **Simple delegation** (most common):\n * ```javascript\n * import { withObserver } from '../utils/ObserverMixin.js';\n * import ObserverSubject from '../core/ObserverSubject.js';\n * \n * class MyClass {\n *     constructor() {\n *         this.observerSubject = new ObserverSubject();\n *     }\n * }\n * \n * // Add observer methods\n * Object.assign(MyClass.prototype, withObserver());\n * ```\n * \n * 2. **With null checking** (for critical paths):\n * ```javascript\n * Object.assign(MyClass.prototype, withObserver({ checkNull: true, className: 'MyClass' }));\n * ```\n * \n * 3. **With custom notification logic**:\n * ```javascript\n * class MyClass {\n *     constructor() {\n *         this.observerSubject = new ObserverSubject();\n *     }\n *     \n *     // Override notifyObservers for custom behavior\n *     notifyObservers(event, data) {\n *         log(`Notifying with event: ${event}`);\n *         this.observerSubject.notifyObservers(this, event, data);\n *     }\n * }\n * \n * // Add subscribe/unsubscribe only\n * Object.assign(MyClass.prototype, withObserver({ excludeNotify: true }));\n * ```\n * \n * @module utils/ObserverMixin\n * @since 0.9.0-alpha\n * @author Marcelo Pereira Barbosa\n * \n * @example\n * // Standard usage (most classes)\n * import { withObserver } from '../utils/ObserverMixin.js';\n * \n * class ReverseGeocoder {\n *     constructor() {\n *         this.observerSubject = new ObserverSubject();\n *     }\n * }\n * Object.assign(ReverseGeocoder.prototype, withObserver());\n * \n * @example\n * // With null checking (for user-facing APIs)\n * class WebGeocodingManager {\n *     constructor() {\n *         this.observerSubject = new ObserverSubject();\n *     }\n * }\n * Object.assign(WebGeocodingManager.prototype, \n *     withObserver({ checkNull: true, className: 'WebGeocodingManager' }));\n */\n\n/**\n * Configuration options for observer mixin.\n * @typedef {Object} ObserverMixinOptions\n * @property {boolean} [checkNull=false] - Whether to validate observer is not null\n * @property {string} [className='Class'] - Class name for logging (if checkNull=true)\n * @property {boolean} [excludeNotify=false] - Exclude notifyObservers method (use custom)\n */\n\n/**\n * Creates an observer mixin with standard delegation methods.\n * \n * Returns an object with subscribe, unsubscribe, and optionally notifyObservers\n * methods that delegate to this.observerSubject. The class must have an\n * observerSubject property initialized before using these methods.\n * \n * @param {ObserverMixinOptions} [options={}] - Configuration options\n * @returns {Object} Object with observer delegation methods\n * \n * @example\n * // Basic usage\n * Object.assign(MyClass.prototype, withObserver());\n * \n * @example\n * // With null checking\n * Object.assign(MyClass.prototype, withObserver({ \n *     checkNull: true, \n *     className: 'MyClass' \n * }));\n */\nexport function withObserver(options = {}) {\n\tconst {\n\t\tcheckNull = false,\n\t\tclassName = 'Class',\n\t\texcludeNotify = false\n\t} = options;\n\n\tconst mixin = {\n\t\t/**\n\t\t * Subscribes an observer to receive notifications.\n\t\t * \n\t\t * @param {Object} observer - Observer object with update() method\n\t\t * @returns {void}\n\t\t */\n\t\tsubscribe(observer) {\n\t\t\tif (checkNull && observer == null) {\n\t\t\t\twarn(`(${className}) Attempted to subscribe a null observer.`);\n\t\t\t\treturn;\n\t\t\t}\n\t\t\tthis.observerSubject.subscribe(observer);\n\t\t},\n\n\t\t/**\n\t\t * Unsubscribes an observer from receiving notifications.\n\t\t * \n\t\t * @param {Object} observer - Observer object to remove\n\t\t * @returns {void}\n\t\t */\n\t\tunsubscribe(observer) {\n\t\t\tthis.observerSubject.unsubscribe(observer);\n\t\t}\n\t};\n\n\t// Add notifyObservers unless explicitly excluded\n\tif (!excludeNotify) {\n\t\t/**\n\t\t * Notifies all subscribed observers with the provided arguments.\n\t\t * \n\t\t * @param {...*} args - Arguments to pass to observer update methods\n\t\t * @returns {void}\n\t\t */\n\t\tmixin.notifyObservers = function(...args) {\n\t\t\tthis.observerSubject.notifyObservers(...args);\n\t\t};\n\t}\n\n\treturn mixin;\n}\n\n/**\n * Default export for convenience.\n * @type {Function}\n */\nexport default withObserver;\n","'use strict';\n\n/**\n * Centralized singleton manager for device geographic position.\n * \n * PositionManager implements the singleton and observer patterns to provide a single\n * source of truth for the current device position. It wraps the browser's Geolocation API,\n * applies multi-layer validation rules (accuracy, distance, time thresholds), and notifies\n * subscribed observers about position changes.\n * \n * Key Features:\n * - Singleton pattern ensures one position state across application\n * - Observer pattern for decoupled position change notifications\n * - Smart filtering prevents excessive processing from GPS noise\n * - Multi-layer validation (accuracy quality, distance OR time threshold)\n * - Integration with GeoPosition for enhanced position data\n * \n * Validation Rules (v0.9.0-alpha):\n * 1. Accuracy Quality: Rejects medium/bad/very bad accuracy on mobile devices\n * 2. Distance OR Time Threshold: Updates if EITHER condition is met:\n *    - Movement ≥ 20 meters OR\n *    - Time elapsed ≥ 30 seconds\n * 3. Event Classification: Distinguishes regular updates (≥50s) from immediate updates (<50s)\n * \n * @module core/PositionManager\n * @pattern Singleton - Only one instance manages position state\n * @pattern Observer - Notifies subscribers of position changes\n * \n * @see {@link GeoPosition} For position data wrapper with convenience methods\n * @see {@link ObserverSubject} For observer pattern implementation\n * @see [Complete Documentation](../../docs/architecture/POSITION_MANAGER.md)\n * \n * @example\n * // Basic usage - get singleton instance\n * const manager = PositionManager.getInstance();\n * \n * @example\n * // Subscribe to position updates\n * const observer = {\n *   update: (positionManager, eventType) => {\n *     if (eventType === PositionManager.strCurrPosUpdate) {\n *       log('Position:', positionManager.latitude, positionManager.longitude);\n *     }\n *   }\n * };\n * manager.subscribe(observer);\n * \n * @example\n * // Update position (typically done by GeolocationService)\n * navigator.geolocation.getCurrentPosition((position) => {\n *   const manager = PositionManager.getInstance();\n *   manager.update(position); // Validates and updates if rules pass\n * });\n * \n * @since 0.6.0-alpha\n * @author Marcelo Pereira Barbosa\n */\n\nimport GeoPosition from './GeoPosition.js';\nimport ObserverSubject from './ObserverSubject.js';\nimport { calculateDistance } from '../utils/distance.js';\nimport { log, warn } from '../utils/logger.js';\nimport { withObserver } from '../utils/ObserverMixin.js';\n\n/**\n * Get configuration - use imported defaults and allow override\n * This makes the module testable and reduces coupling\n */\nlet setupParams = null;\n\n/**\n * Initialize setupParams - called when module loads or can be overridden for testing.\n * \n * Sets the configuration object for position tracking parameters. This function\n * allows runtime configuration override, which is particularly useful for testing\n * scenarios where different configurations need to be tested.\n * \n * @param {Object} config - Configuration object with tracking parameters\n * @param {string[]} config.notAcceptedAccuracy - Array of unacceptable accuracy levels\n * @param {number} config.minimumDistanceChange - Minimum distance change in meters to trigger update\n * @param {number} config.trackingInterval - Tracking interval in milliseconds\n * @returns {void}\n * \n * @example\n * // Initialize with custom configuration\n * initializeConfig({\n *   notAcceptedAccuracy: ['medium', 'bad'],\n *   minimumDistanceChange: 50,\n *   trackingInterval: 30000\n * });\n * \n * @since 0.9.0-alpha\n * @author Marcelo Pereira Barbosa\n */\nexport function initializeConfig(config) {\n\tsetupParams = config;\n}\n\n// Initialize with defaults if available\ntry {\n\tconst { createDefaultConfig } = await import('../config/defaults.js');\n\tsetupParams = createDefaultConfig();\n} catch (err) {\n\t// If config not available, use minimal defaults\n\tsetupParams = {\n\t\tnotAcceptedAccuracy: ['medium', 'bad', 'very bad'],\n\t\tminimumDistanceChange: 20,\n\t\ttrackingInterval: 50000\n\t};\n}\n\n/**\n * Manages the current geolocation position using singleton and observer design patterns.\n * \n * This class provides centralized management of the user's current geographic position,\n * implementing timing constraints, accuracy validation, and distance-based filtering\n * to ensure position updates are meaningful and efficient. It notifies subscribed\n * observers when position changes occur.\n * \n * The PositionManager enforces several validation rules:\n * - Minimum time interval between updates (50 seconds by default)\n * - Minimum distance change threshold (20 meters by default)\n * - Accuracy quality requirements (rejects medium/bad/very bad accuracy)\n * \n * @class PositionManager\n * @implements {Observer} - Implements observer pattern for position change notifications\n */\nclass PositionManager {\n\t/**\n\t * Singleton instance holder. Only one PositionManager exists per application.\n\t * @static\n\t * @type {PositionManager|null}\n\t * @private\n\t */\n\tstatic instance = null;\n\n\t/**\n\t * Event string constant fired when position is successfully updated.\n\t * @static\n\t * @type {string}\n\t * @readonly\n\t */\n\tstatic strCurrPosUpdate = \"PositionManager updated\";\n\n\t/**\n\t * Event string constant fired when position update is rejected due to validation rules.\n\t * @static\n\t * @type {string}\n\t * @readonly\n\t */\n\tstatic strCurrPosNotUpdate = \"PositionManager not updated\";\n\n\t/**\n\t * Event string constant fired when position is successfully updated and must be immediately processed.\n\t * @static\n\t * @type {string}\n\t * @readonly\n\t */\n\tstatic strImmediateAddressUpdate = 'Immediate address update';\n\n\t/**\n\t * Gets or creates the singleton PositionManager instance.\n\t * \n\t * Implements the singleton pattern ensuring only one PositionManager instance\n\t * exists throughout the application lifecycle. If a position is provided when\n\t * an instance already exists, it will attempt to update the existing instance.\n\t * \n\t * @static\n\t * @param {GeolocationPosition} [position] - HTML5 Geolocation API Position object\n\t * @param {GeolocationCoordinates} [position.coords] - Coordinate information\n\t * @param {number} [position.coords.latitude] - Latitude in decimal degrees\n\t * @param {number} [position.coords.longitude] - Longitude in decimal degrees  \n\t * @param {number} [position.coords.accuracy] - Accuracy in meters\n\t * @param {number} [position.timestamp] - Timestamp when position was acquired\n\t * @returns {PositionManager} The singleton PositionManager instance\n\t * \n\t * @example\n\t * // Create initial instance\n\t * const manager = PositionManager.getInstance();\n\t * \n\t * @example  \n\t * // Create or update with position data\n\t * navigator.geolocation.getCurrentPosition((position) => {\n\t *   const manager = PositionManager.getInstance(position);\n\t *   log(manager.latitude, manager.longitude);\n\t * });\n\t * \n\t * @since 0.6.0-alpha\n\t */\n\tstatic getInstance(position) {\n\t\tif (!PositionManager.instance) {\n\t\t\tPositionManager.instance = new PositionManager(position);\n\t\t} else if (position) {\n\t\t\tPositionManager.instance.update(position);\n\t\t}\n\t\treturn PositionManager.instance;\n\t}\n\n\t/**\n\t * Creates a new PositionManager instance.\n\t * \n\t * Initializes the position manager with an ObserverSubject for immutable observer \n\t * management and optional initial position data. This constructor is typically called \n\t * internally by the getInstance() method to maintain the singleton pattern.\n\t * \n\t * @param {GeolocationPosition} [position] - Initial position data\n\t * @param {GeolocationCoordinates} [position.coords] - Coordinate information\n\t * @param {number} [position.coords.latitude] - Latitude in decimal degrees\n\t * @param {number} [position.coords.longitude] - Longitude in decimal degrees\n\t * @param {number} [position.coords.accuracy] - Accuracy in meters\n\t * @param {number} [position.timestamp] - Timestamp when position was acquired\n\t * \n\t * @example\n\t * // Typically used internally by getInstance()\n\t * const manager = new PositionManager(geolocationPosition);\n\t * \n\t * @since 0.6.0-alpha\n\t */\n\tconstructor(position) {\n\t\tthis.observerSubject = new ObserverSubject();\n\t\tthis.tsPosicaoAtual = null;\n\t\tthis.lastModified = null;\n\t\tif (position) {\n\t\t\tthis.update(position);\n\t\t}\n\t}\n\n\t/**\n\t * Gets the observers array for backward compatibility.\n\t * @private\n\t * @returns {Array} Array of subscribed observers\n\t */\n\tget observers() {\n\t\treturn this.observerSubject.observers;\n\t}\n\n\t/**\n\t * Subscribes an observer to position change notifications.\n\t * \n\t * Implements the observer pattern by delegating to ObserverSubject, which manages\n\t * observers immutably. Observers will be notified when position updates occur. \n\t * Observers must implement an update() method that accepts (positionManager, eventType) parameters.\n\t * \n\t * **Note:** Observer management uses immutable array updates via ObserverSubject,\n\t * ensuring referential transparency for subscribe/unsubscribe operations.\n\t * \n\t * @param {Object} observer - Observer object to subscribe\n\t * @param {Function} observer.update - Method called on position changes\n\t * @returns {void}\n\t * \n\t * @example\n\t * const myObserver = {\n\t *   update: (positionManager, event) => {\n\t *     log('Position event:', event, positionManager.latitude);\n\t *   }\n\t * };\n\t * PositionManager.getInstance().subscribe(myObserver);\n\t * \n\t * @since 0.6.0-alpha\n\t */\n\n\t/**\n\t * Proxy properties from lastPosition for direct access\n\t */\n\tget latitude() {\n\t\treturn this.lastPosition?.latitude;\n\t}\n\n\tget longitude() {\n\t\treturn this.lastPosition?.longitude;\n\t}\n\n\tget accuracy() {\n\t\treturn this.lastPosition?.accuracy;\n\t}\n\n\tget accuracyQuality() {\n\t\treturn this.lastPosition?.accuracyQuality;\n\t}\n\n\tget altitude() {\n\t\treturn this.lastPosition?.altitude;\n\t}\n\n\tget heading() {\n\t\treturn this.lastPosition?.heading;\n\t}\n\n\tget speed() {\n\t\treturn this.lastPosition?.speed;\n\t}\n\n\tget timestamp() {\n\t\treturn this.lastPosition?.timestamp;\n\t}\n\n\t/**\n\t * Notifies all observers with the given event type.\n\t * \n\t * @private\n\t * @param {string} posEvent - Event type constant\n\t * @param {*} data - Optional data to pass to observers\n\t * @param {Error} error - Optional error object\n\t */\n\tnotifyObservers(posEvent, data = null, error = null) {\n\t\tthis.observerSubject.notifyObservers(this, posEvent, data, error);\n\t}\n\n\t/**\n\t * Updates the position with validation and filtering rules.\n\t * \n\t * This is the core method that processes new position data with multiple\n\t * validation layers to ensure only meaningful position updates are accepted:\n\t * \n\t * Validation Rules:\n\t * 1. Position validity: Must have valid position object with timestamp\n\t * 2. Time constraint: Must wait at least 50 seconds (trackingInterval) between updates\n\t * 3. Accuracy requirement: Rejects medium/bad/very bad accuracy positions  \n\t * 4. Distance threshold: Must move at least 20 meters (minimumDistanceChange)\n\t * \n\t * When validation passes, updates all position properties and notifies observers.\n\t * When validation fails, notifies observers with the rejection reason.\n\t * \n\t * @param {GeolocationPosition} position - New position data from Geolocation API\n\t * @param {GeolocationCoordinates} position.coords - Coordinate information\n\t * @param {number} position.coords.latitude - Latitude in decimal degrees\n\t * @param {number} position.coords.longitude - Longitude in decimal degrees\n\t * @param {number} position.coords.accuracy - Accuracy in meters\n\t * @param {number} position.coords.altitude - Altitude in meters (may be null)\n\t * @param {number} position.coords.altitudeAccuracy - Altitude accuracy in meters (may be null)  \n\t * @param {number} position.coords.heading - Compass heading in degrees (may be null)\n\t * @param {number} position.coords.speed - Speed in meters/second (may be null)\n\t * @param {number} position.timestamp - Timestamp when position was acquired\n\t * @returns {void}\n\t * \n\t * @fires PositionManager#strCurrPosUpdate - When position successfully updated\n\t * @fires PositionManager#strCurrPosNotUpdate - When position rejected by validation\n\t * \n\t * @example\n\t * // Update with new position (typically from Geolocation API)\n\t * navigator.geolocation.getCurrentPosition((position) => {\n\t *   const manager = PositionManager.getInstance();\n\t *   manager.update(position); // Validates and updates if rules pass\n\t * });\n\t * \n\t * @see {@link https://developer.mozilla.org/en-US/docs/Web/API/GeolocationPosition} GeolocationPosition\n\t * @since 0.6.0-alpha\n\t */\n\tupdate(position) {\n\t\tlet bUpdateCurrPos = true;\n\t\tlet error = null;\n\n\t\tlog(\"(PositionManager) update called with position:\", position);\n\t\tlog(\"(PositionManager) lastPosition:\", this.lastPosition);\n\t\t// Verifica se a posição é válida\n\t\tif (!position || !position.timestamp) {\n\t\t\twarn(\"(PositionManager) Invalid position data:\", position);\n\t\t\treturn;\n\t\t}\n\n\t\t// Verifica se a precisão é boa o suficiente\n\t\tif (\n\t\t\tsetupParams.notAcceptedAccuracy && \n\t\t\tArray.isArray(setupParams.notAcceptedAccuracy) &&\n\t\t\tsetupParams.notAcceptedAccuracy.includes(\n\t\t\t\tGeoPosition.getAccuracyQuality(position.coords.accuracy)\n\t\t\t)\n\t\t) {\n\t\t\tbUpdateCurrPos = false;\n\t\t\terror = { name: \"AccuracyError\", message: \"Accuracy is not good enough\" };\n\t\t\twarn(\n\t\t\t\t\"(PositionManager) Accuracy not good enough:\",\n\t\t\t\tposition.coords.accuracy,\n\t\t\t);\n\t\t}\n\t\t\n\t\t// DISTANCE OR TIME VALIDATION (v0.9.0-alpha):\n\t\t// Update position if EITHER condition is met:\n\t\t// 1. Distance > minimumDistanceChange (20 meters) OR\n\t\t// 2. Time elapsed > minimumTimeChange (30 seconds)\n\t\t// This ensures responsive updates even during slow movement\n\t\tif (\n\t\t\tthis.lastPosition &&\n\t\t\tposition &&\n\t\t\tthis.lastPosition.latitude &&\n\t\t\tthis.lastPosition.longitude &&\n\t\t\tposition.coords\n\t\t) {\n\t\t\tconst distance = calculateDistance(\n\t\t\t\tthis.lastPosition.latitude,\n\t\t\t\tthis.lastPosition.longitude,\n\t\t\t\tposition.coords.latitude,\n\t\t\t\tposition.coords.longitude,\n\t\t\t);\n\t\t\t\n\t\t\tconst timeElapsed = position.timestamp - (this.lastModified || 0);\n\t\t\tconst timeElapsedSeconds = (timeElapsed / 1000).toFixed(1);\n\t\t\t\n\t\t\t// Check if EITHER distance OR time threshold is exceeded\n\t\t\tconst distanceExceeded = distance >= setupParams.minimumDistanceChange;\n\t\t\tconst timeExceeded = timeElapsed >= setupParams.minimumTimeChange;\n\t\t\t\n\t\t\tif (!distanceExceeded && !timeExceeded) {\n\t\t\t\tbUpdateCurrPos = false;\n\t\t\t\terror = { \n\t\t\t\t\tname: \"DistanceAndTimeError\", \n\t\t\t\t\tmessage: `Neither distance (${distance.toFixed(1)}m < ${setupParams.minimumDistanceChange}m) nor time (${timeElapsedSeconds}s < ${setupParams.minimumTimeChange / 1000}s) threshold met`\n\t\t\t\t};\n\t\t\t\twarn(\n\t\t\t\t\t\"(PositionManager) Update blocked - distance:\",\n\t\t\t\t\tdistance.toFixed(1) + \"m\",\n\t\t\t\t\t\"time:\",\n\t\t\t\t\ttimeElapsedSeconds + \"s\"\n\t\t\t\t);\n\t\t\t} else {\n\t\t\t\t// Log which condition triggered the update\n\t\t\t\tif (distanceExceeded && timeExceeded) {\n\t\t\t\t\tlog(\n\t\t\t\t\t\t\"(PositionManager) Update triggered - BOTH conditions met - distance:\",\n\t\t\t\t\t\tdistance.toFixed(1) + \"m\",\n\t\t\t\t\t\t\"time:\",\n\t\t\t\t\t\ttimeElapsedSeconds + \"s\"\n\t\t\t\t\t);\n\t\t\t\t} else if (distanceExceeded) {\n\t\t\t\t\tlog(\n\t\t\t\t\t\t\"(PositionManager) Update triggered by DISTANCE -\",\n\t\t\t\t\t\tdistance.toFixed(1) + \"m\",\n\t\t\t\t\t\t\"(time:\",\n\t\t\t\t\t\ttimeElapsedSeconds + \"s)\"\n\t\t\t\t\t);\n\t\t\t\t} else {\n\t\t\t\t\tlog(\n\t\t\t\t\t\t\"(PositionManager) Update triggered by TIME -\",\n\t\t\t\t\t\ttimeElapsedSeconds + \"s\",\n\t\t\t\t\t\t\"(distance:\",\n\t\t\t\t\t\tdistance.toFixed(1) + \"m)\"\n\t\t\t\t\t);\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\n\t\tif (!bUpdateCurrPos) {\n\t\t\tthis.notifyObservers(PositionManager.strCurrPosNotUpdate, null, error);\n\t\t\treturn;\n\t\t}\n\n\t\tlet posEvent = \"\";\n\n\t\tif (position.timestamp - (this.lastModified || 0) < setupParams.trackingInterval) {\n\t\t\tlet errorMessage = `Less than ${setupParams.trackingInterval / 1000} seconds since last update: ${(position.timestamp - (this.lastModified || 0)) / 1000} seconds`;\n\t\t\terror = {\n\t\t\t\tname: \"ElapseTimeError\",\n\t\t\t\tmessage: errorMessage,\n\t\t\t};\n\t\t\twarn(\"(PositionManager) \" + errorMessage);\n\t\t\tposEvent = PositionManager.strImmediateAddressUpdate;\n\t\t} else {\n\t\t\tposEvent = PositionManager.strCurrPosUpdate;\n\t\t}\n\n\t\t// Atualiza a posição apenas se tiver passado mais de 1 minuto\n\t\tthis.lastPosition = new GeoPosition(position);\n\t\tthis.position = this.lastPosition;\n\t\tthis.lastModified = position.timestamp;\n\t\tthis.notifyObservers(posEvent, null, error);\n\t}\n\n\t/**\n\t * Returns a string representation of the current position.\n\t * \n\t * Provides a formatted summary of key position properties for debugging\n\t * and logging purposes. Includes class name and essential position data.\n\t * \n\t * @returns {string} Formatted string with position details\n\t * \n\t * @example\n\t * const manager = PositionManager.getInstance(position);\n\t * log(manager.toString());\n\t * // Output: \"PositionManager: -23.5505, -46.6333, good, 760, 0, 0, 1634567890123\"\n\t * \n\t * @since 0.6.0-alpha\n\t */\n\ttoString() {\n\t\tlet position = this.lastPosition || {};\n\t\tif (!position || !this.latitude || !this.longitude) {\n\t\t\treturn `${this.constructor.name}: No position data`;\n\t\t}\n\t\treturn `${this.constructor.name}: ${position.latitude}, ${position.longitude}, ${position.accuracyQuality}, ${position.altitude}, ${position.speed}, ${position.heading}, ${position.timestamp}`;\n\t}\n}\n\n// Apply observer mixin for subscribe/unsubscribe delegation (notifyObservers has custom signature)\nObject.assign(PositionManager.prototype, withObserver({ excludeNotify: true }));\n\nexport default PositionManager;\n","'use strict';\n\n/**\n * GeocodingState - Centralized state management for geocoding data\n * \n * @fileoverview Manages the current position and coordinate state for the geocoding workflow.\n * Implements the Observer pattern to notify subscribers of state changes.\n * This class follows the Single Responsibility Principle by focusing solely on state management.\n * \n * **Design Principles:**\n * - **Single Responsibility:** State management only\n * - **Immutability:** Returns defensive copies of state\n * - **Observer Pattern:** Notify observers of state changes\n * - **Encapsulation:** Private state with public accessors\n * \n * @module core/GeocodingState\n * @since 0.9.0-alpha - Extracted from WebGeocodingManager during Phase 17 refactoring\n * @author Marcelo Pereira Barbosa\n * \n * @requires core/GeoPosition\n * @requires utils/logger\n * \n * @example\n * // Basic usage\n * import GeocodingState from './core/GeocodingState.js';\n * \n * const state = new GeocodingState();\n * \n * // Subscribe to state changes\n * state.subscribe((stateSnapshot) => {\n *   log('Position updated:', stateSnapshot.position);\n * });\n * \n * // Set position (triggers notification)\n * const position = new GeoPosition(browserPosition);\n * state.setPosition(position);\n * \n * @example\n * // Get current state\n * const coords = state.getCurrentCoordinates();\n * log(coords.latitude, coords.longitude);\n * \n * const position = state.getCurrentPosition();\n * log(position.accuracy, position.accuracyQuality);\n */\n\nimport GeoPosition from './GeoPosition.js';\nimport { warn } from '../utils/logger.js';\n\n/**\n * GeocodingState class - Manages position and coordinate state\n * \n * @class\n */\nclass GeocodingState {\n    /**\n     * Creates a new GeocodingState instance\n     * \n     * @constructor\n     */\n    constructor() {\n        /**\n         * Current position (GeoPosition instance)\n         * @type {GeoPosition|null}\n         * @private\n         */\n        this._currentPosition = null;\n\n        /**\n         * Current coordinates (extracted from position)\n         * @type {Object|null}\n         * @private\n         */\n        this._currentCoordinates = null;\n\n        /**\n         * State change observers (callbacks)\n         * @type {Function[]}\n         * @private\n         */\n        this._observers = [];\n    }\n\n    /**\n     * Set current position and notify observers\n     * \n     * @param {GeoPosition|null} position - The new position, or null to clear\n     * @throws {TypeError} If position is not a GeoPosition instance or null\n     * @returns {GeocodingState} This instance for chaining\n     * \n     * @example\n     * const position = new GeoPosition(browserPosition);\n     * state.setPosition(position);\n     * \n     * @example\n     * state.setPosition(null); // Clear position\n     */\n    setPosition(position) {\n        if (position !== null && !(position instanceof GeoPosition)) {\n            throw new TypeError('GeocodingState: position must be a GeoPosition instance or null');\n        }\n\n        this._currentPosition = position;\n        this._currentCoordinates = position ? {\n            latitude: position.latitude,\n            longitude: position.longitude\n        } : null;\n\n        if (position !== null) {\n            this._notifyObservers();\n        }\n        \n        return this;\n    }\n\n    /**\n     * Get current position\n     * \n     * @returns {GeoPosition|null} The current position or null if not set\n     * \n     * @example\n     * const position = state.getCurrentPosition();\n     * if (position) {\n     *   log(position.latitude, position.accuracyQuality);\n     * }\n     */\n    getCurrentPosition() {\n        return this._currentPosition;\n    }\n\n    /**\n     * Get current coordinates (defensive copy)\n     * \n     * @returns {Object|null} Coordinates object {latitude, longitude} or null\n     * \n     * @example\n     * const coords = state.getCurrentCoordinates();\n     * if (coords) {\n     *   log(`Lat: ${coords.latitude}, Lon: ${coords.longitude}`);\n     * }\n     */\n    getCurrentCoordinates() {\n        return this._currentCoordinates ? { ...this._currentCoordinates } : null;\n    }\n\n    /**\n     * Check if position is available\n     * \n     * @returns {boolean} True if position is set\n     * \n     * @example\n     * if (state.hasPosition()) {\n     *   const coords = state.getCurrentCoordinates();\n     *   // Use coordinates...\n     * }\n     */\n    hasPosition() {\n        return this._currentPosition !== null;\n    }\n\n    /**\n     * Subscribe to state changes\n     * \n     * Callback receives a state snapshot object with position and coordinates.\n     * \n     * @param {Function} callback - Called when state changes: (stateSnapshot) => void\n     * @returns {Function} Unsubscribe function\n     * @throws {TypeError} If callback is not a function\n     * \n     * @example\n     * const unsubscribe = state.subscribe((stateSnapshot) => {\n     *   log('New position:', stateSnapshot.position);\n     *   log('Coordinates:', stateSnapshot.coordinates);\n     * });\n     * \n     * // Later, unsubscribe\n     * unsubscribe();\n     */\n    subscribe(callback) {\n        if (typeof callback !== 'function') {\n            throw new TypeError('GeocodingState: callback must be a function');\n        }\n        this._observers.push(callback);\n        \n        // Return unsubscribe function\n        return () => {\n            const index = this._observers.indexOf(callback);\n            if (index > -1) {\n                this._observers.splice(index, 1);\n            }\n        };\n    }\n\n    /**\n     * Unsubscribe from state changes\n     * \n     * @param {Function} callback - The callback to remove\n     * @returns {boolean} True if callback was found and removed\n     * \n     * @example\n     * const handler = (state) => log(state);\n     * state.subscribe(handler);\n     * // Later...\n     * state.unsubscribe(handler);\n     */\n    unsubscribe(callback) {\n        const index = this._observers.indexOf(callback);\n        if (index > -1) {\n            this._observers.splice(index, 1);\n            return true;\n        }\n        return false;\n    }\n\n    /**\n     * Get number of active observers\n     * \n     * @returns {number} Number of subscribed observers\n     * \n     * @example\n     * log(`Active observers: ${state.getObserverCount()}`);\n     */\n    getObserverCount() {\n        return this._observers.length;\n    }\n\n    /**\n     * Clear all observers\n     * \n     * Useful for cleanup or testing.\n     * \n     * @example\n     * state.clearObservers();\n     */\n    clearObservers() {\n        this._observers = [];\n    }\n\n    /**\n     * Clear current position state\n     * \n     * @example\n     * state.clear();\n     * log(state.hasPosition()); // false\n     */\n    clear() {\n        this._currentPosition = null;\n        this._currentCoordinates = null;\n    }\n\n    /**\n     * Notify all observers of state change\n     * \n     * Observers receive a state snapshot with position and coordinates.\n     * Errors in observer callbacks are caught and logged.\n     * \n     * @private\n     */\n    _notifyObservers() {\n        const stateSnapshot = {\n            position: this._currentPosition,\n            coordinates: this.getCurrentCoordinates()\n        };\n\n        this._observers.forEach(callback => {\n            try {\n                callback(stateSnapshot);\n            } catch (error) {\n                warn('GeocodingState: Error notifying observer', error);\n            }\n        });\n    }\n\n    /**\n     * Get string representation of current state\n     * \n     * @returns {string} State summary\n     * \n     * @example\n     * log(state.toString());\n     * // \"GeocodingState: position: available, coordinates: (lat, lon), observers: 2\"\n     */\n    toString() {\n        const hasPos = this._currentPosition ? 'available' : 'null';\n        const coords = this._currentCoordinates ?\n            `(${this._currentCoordinates.latitude.toFixed(4)}, ${this._currentCoordinates.longitude.toFixed(4)})` :\n            'null';\n        return `GeocodingState: position: ${hasPos}, coordinates: ${coords}, observers: ${this._observers.length}`;\n    }\n}\n\nexport default GeocodingState;\n"],"file":"core-8BMT7-GD.js"}git 